import{_ as s,r as n,o,c as r,b as t,d as e,e as i,a as l}from"./app-2a089349.js";const d={},c=t("h1",{id:"how-to-create-stripe-pages-manually",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#how-to-create-stripe-pages-manually","aria-hidden":"true"},"#"),e(" How to Create Stripe Pages Manually?")],-1),p=t("strong",null,'"Create Pages"',-1),h={href:"https://ultimatemember.github.io/docs-v3/um-stripe/article/1609-stripe---setting-up-stripe-success-and-cancel-payment-pages.html",target:"_blank",rel:"noopener noreferrer"},g=l('<h2 id="create-stripe-pages-manually" tabindex="-1"><a class="header-anchor" href="#create-stripe-pages-manually" aria-hidden="true">#</a> Create Stripe Pages Manually</h2><p>If these pages haven&#39;t been generated automatically or if you&#39;ve unintentionally deleted the Stripe pages, you can explore the steps outlined below as an alternative solution:</p><h3 id="already-subscribed-page" tabindex="-1"><a class="header-anchor" href="#already-subscribed-page" aria-hidden="true">#</a> Already subscribed page</h3><ol><li><p>Go to wp-admin&gt;Pages. Click on the <strong>&#39;Add new page&#39;</strong> button.</p></li><li><p>Add the page title <strong>&#39;Already subscribed&#39;</strong></p></li><li><p>In the content area, add the default text and shortcode for the customer portal button: ``` You already have a subscription. You can view/manage your existing subscription via your [ultimatemember_stripe_customer_portal type=&quot;link&quot; label=&quot;customer portal&quot;].</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code></code></pre><div class="line-numbers" aria-hidden="true"></div></div></li><li><p>Click the <strong>&#39;Publish</strong>&#39; button to save the page.</p></li></ol><h3 id="customer-portal-page" tabindex="-1"><a class="header-anchor" href="#customer-portal-page" aria-hidden="true">#</a> <strong>Customer Portal page</strong></h3><ol><li>Go to wp-admin&gt;Pages. Click on the <strong>&#39;Add new page&#39;</strong> button.</li><li>Add the page title <strong>&#39;Customer Portal&#39;</strong></li><li>Click the <strong>&#39;Publish&#39;</strong> button to save the page.</li></ol><h3 id="payment-canceled-page" tabindex="-1"><a class="header-anchor" href="#payment-canceled-page" aria-hidden="true">#</a> <strong>Payment canceled page</strong></h3><ol><li><p>Go to wp-admin&gt;Pages. Click on the <strong>&#39;Add new page&#39;</strong> button.</p></li><li><p>Add the page title <strong>&#39;Payment canceled&#39;</strong></p></li><li><p>In the content area, add the default text or customize it to your preference: ``` The transaction has been cancelled. No payment has been taken.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code></code></pre><div class="line-numbers" aria-hidden="true"></div></div></li><li><p>Click the <strong>&#39;Publish&#39;</strong> button to save the page.</p></li></ol><h3 id="payment-successful-page" tabindex="-1"><a class="header-anchor" href="#payment-successful-page" aria-hidden="true">#</a> Payment successful page</h3><ol><li><p>Go to wp-admin&gt;Pages. Click on the <strong>&#39;Add new page&#39;</strong> button.</p></li><li><p>Add the page title <strong>&#39;Payment successful&#39;</strong></p></li><li><p>In the content area, add the default content, which is the <a href="/docs-v3/um-stripe/article/1616-stripe-shortcodes-reference">shortcode</a> to display the user&#39;s order details: ``` [ultimatemember_stripe_checkout_order_details]</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code></code></pre><div class="line-numbers" aria-hidden="true"></div></div></li><li><p>Click the <strong>&#39;Publish&#39;</strong> button to save the page.</p></li></ol><h3 id="stripe-checkout-url-page" tabindex="-1"><a class="header-anchor" href="#stripe-checkout-url-page" aria-hidden="true">#</a> Stripe Checkout URL page</h3><ol><li>Go to wp-admin&gt;Pages. Click on the <strong>&#39;Add new page&#39;</strong> button.</li><li>Add the page title <strong>&#39;Stripe Checkout URL&#39;</strong></li><li>Click the <strong>&#39;Publish&#39;</strong> button to save the page.</li></ol><h3 id="payment-checkout-page" tabindex="-1"><a class="header-anchor" href="#payment-checkout-page" aria-hidden="true">#</a> Payment Checkout Page</h3><ol><li><p>Go to wp-admin&gt;Pages. Click on the <strong>&#39;Add new page&#39;</strong> button.</p></li><li><p>Add the page title <strong>&#39;Payment Checkout&#39;</strong></p></li><li><p>In the content area, add the default content, which is the shortcode to display the checkout form within your site. This integration empowers users to finalize their purchases seamlessly, directly on your site, without needing to navigate away.: ``` [ultimatemember_stripe_checkout_order_details]</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code></code></pre><div class="line-numbers" aria-hidden="true"></div></div></li><li><p>Click the <strong>&#39;Publish&#39;</strong> button to save the page.</p></li></ol><p>After you have manually created all the required Stripe pages, assign the pages in <strong>WP Admin &gt; UM &gt; Settings &gt; General &gt; Pages.</strong></p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65d4c908e3adc6007de13b9c/file-CpifXpo5hP.png" alt=""></p>',16);function u(m,b){const a=n("ExternalLinkIcon");return o(),r("div",null,[c,t("p",null,[e("Upon installing the Stripe extension on your WordPress website, a notification will appear at the top of your wp-admin page, providing information about the necessary pages to be created. To generate these pages, click on the "),p,e(" button. After completing this step, the Stripe Pages (Success, Cancel, Already Subscribed, Stripe Checkout URL, and Customer Portal pages) will be automatically added in the wp-admin>Pages. For further explanation about the pages and detailed instructions for setting them up, please refer to this "),t("a",h,[e("article"),i(a)]),e(" .")]),g])}const f=s(d,[["render",u],["__file","1900-how-to-create-stripe-pages-manually.html.vue"]]);export{f as default};
